script.text:

function activeAdjustDeductablePIT(f) {f._controlFocus = f.getItem('loai_tn');}
function initAdjustDeductablePIT(f) {
  if (f._action == 'New') {
    f.setItemValue('nam', f.grid._year);
    var o = f.getItem('ma_dvcs');
    o.value = f._unitCode;
    f.getItem('ten_dvcs%l').value = f._unitName;
    f.live(f.getItem('loai_tn'));
  }
}
